onOptionChange:
{{
storeValue("selectedDepartment", "")   // 🔥 RESET DEPARTMENT

.then(() =>
  storeValue("selectedPO", Select_PO.selectedOptionValue)
)
.then(() =>
  storeValue(
    "currentVersion",
    "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === "x" ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    })
  )
)
.then(() => GetPM.run())

.then(() => GetPODeliverablesPM.run())
.then(() => GetPOGroupTestsPM.run())

.then(() => GetPONREPM.run())
.then(() => GetPMAnswers.run())
.then(() => GetPMQuestion.run())

.then(() => {

  const existing = {};

  (GetAnswers.data || []).forEach(a => {
    existing[a.QuestionId] = {
      YesNo: a.YesNo,
      Answer: a.Answer,
      AnsweredBy: a.AnsweredBy,
      AnsweredDate: a.AnsweredDate,

      ResponsiblePerson: a.ResponsiblePerson,
      Action: a.Action,
      DueDate: a.DueDate
    };
  });

  return storeValue("answers", existing)
    .then(() =>
      storeValue(
        "originalAnswers",
        JSON.parse(JSON.stringify(existing))
      )
    );

});
}}
